body:
The CMakeLists.txt from examples in this repo are all using C++ as test bench. I was wonder if anyone can help to provide an example of CMakeLists.txt for SystemVerilog only project. Below is my test code. 

It can be compiled with `verilator --binary factory-method-example.sv` without problem.

Example SystemVerilog file: factory-method-example.sv

```
    interface class Shape;
        pure virtual function void draw();
    endclass
    
    class Rectangle implements Shape;
        function void draw();
            $display("Drawing a rectangle");
        endfunction
    endclass
    
    class Circle implements Shape;
        function void draw();
            $display("Drawing a circle");
        endfunction
    endclass
    
    class ShapeFactory;
        static function Shape createShape(string shapeType);
            if (shapeType == "rectangle") begin
                Rectangle newShape = new();
                return newShape;
            end
            else if (shapeType == "circle") begin
                Circle newShape = new();
                return newShape;
            end
            else begin
                $display("Invalid shape type");
                return null;
            end
        endfunction
    endclass
    
    module top;
        Shape myShape;
        initial begin
            myShape = ShapeFactory::createShape("rectangle");
            myShape.draw();
            myShape = ShapeFactory::createShape("circle");
            myShape.draw();
            myShape = ShapeFactory::createShape("triangle");
            if (myShape != null) begin
                myShape.draw();
            end
            $finish;
        end
    endmodule
```

I tried CMakeLists.txt as below
```
    cmake_minimum_required(VERSION 3.12)
    project(factory_method_example)
    
    find_package(verilator HINTS $ENV{VERILATOR_ROOT} ${VERILATOR_ROOT})
    
    if (NOT verilator_FOUND)
      message(FATAL_ERROR "Verilator was not found. Either install it, or set the VERILATOR_ROOT environment variable")
    endif()
    
    # Create a new executable target that will contain all your sources
    add_executable(example)
    
    # Add the Verilated circuit to the target
    verilate(example
      SOURCES factory-method-example.sv
      TOP_MODULE top)
```

But I got error as below:
```
    [ 90%] Building CXX object CMakeFiles/example.dir/opt/homebrew/share/verilator/include/verilated_threads.cpp.o
    [ 93%] Linking CXX executable example
    Undefined symbols for architecture arm64:
      "_main", referenced from:
         implicit entry/start for main executable
    ld: symbol(s) not found for architecture arm64
    clang: error: linker command failed with exit code 1 (use -v to see invocation)
    gmake[2]: *** [CMakeFiles/example.dir/build.make:618: example] Error 1
    gmake[1]: *** [CMakeFiles/Makefile2:83: CMakeFiles/example.dir/all] Error 2
    gmake: *** [Makefile:91: all] Error 2
```

